class TraceWriter:
    """Writes reviewable JSONL traces for every run."""

    def __init__(self, run_dir: Path):
        self.run_dir = run_dir
        self.trace_path = run_dir / "trace.jsonl"
        self.sse_path = run_dir / "sse.jsonl"

    def write_trace(self, *, kind: str, payload: dict[str, Any]) -> None:
        entry = {
            "timestamp": datetime.now(UTC).isoformat(),
            "kind": kind,
            **payload,
        }
        self._append(self.trace_path, entry)

    def write_sse(self, *, event: str, data: dict[str, Any]) -> None:
        self._append(
            self.sse_path,
            {
                "timestamp": datetime.now(UTC).isoformat(),
                "event": event,
                "data": data,
            },
        )

    def write_report(self, report: dict[str, Any]) -> None:
        (self.run_dir / "final_report.json").write_text(json.dumps(report, indent=2))

    def write_prompt_artifacts(
        self,
        *,
        system_instruction: str,
        request_prompt: str,
    ) -> None:
        prompt_dir = self.run_dir / "prompts"
        prompt_dir.mkdir(parents=True, exist_ok=True)
        (prompt_dir / "system_instruction.txt").write_text(
            system_instruction,
            encoding="utf-8",
        )
        (prompt_dir / "request_prompt.txt").write_text(
            request_prompt,
            encoding="utf-8",
        )

    def _append(self, path: Path, payload: dict[str, Any]) -> None:
        path.parent.mkdir(parents=True, exist_ok=True)
        with path.open("a", encoding="utf-8") as handle:
            handle.write(json.dumps(payload))
            handle.write("\n")


class MlflowRunRecorder:
    """Logs config, run params, and saved artifacts into MLflow when enabled."""

    def __init__(
        self,
        *,
        run_id: str,
        run_dir: Path,
        config_path: Path,
        config: InvoiceAgentConfig,
        prompt: str | None,
    ) -> None:
        self.run_id = run_id
        self.run_dir = run_dir
        self.config_path = config_path
        self.config = config
        self.prompt = prompt
        self.enabled = mlflow is not None and config.tracing.enabled
        self._run_active = False
        self.version_tracking: VersionTrackingMetadata | None = None
        self._git_versioning_enabled = False

    def start(self) -> None:
        if not self.enabled:
            return

        try:
            tracking_uri = self.config.tracing.tracking_uri or self._default_tracking_uri()
            mlflow.set_tracking_uri(tracking_uri)
            if self.config.tracing.tracking_uri:
                mlflow.set_experiment(self.config.tracing.experiment_name)
            else:
                experiment_id = self._ensure_local_experiment(tracking_uri)
                mlflow.set_experiment(experiment_id=experiment_id)
            self._bootstrap_git_version_tracking()
            if (
                self.config.tracing.enable_async_logging
                and hasattr(mlflow, "config")
                and hasattr(mlflow.config, "enable_async_logging")
            ):
                mlflow.config.enable_async_logging()
            mlflow.start_run(run_name=self.run_id)
            self._run_active = True

            self._log_version_tracking_tags()
            for key, value in {
                "run_id": self.run_id,
                "app": self.config.runtime.app_name,
                "planner_mode": self.config.runtime.planner_mode,
                **self.config.tracing.tags,
            }.items():
                mlflow.set_tag(key, str(value))
            mlflow.log_params(flatten_mlflow_params(self.config))

            if self.config.tracing.log_config_artifact:
                config_artifact = self.run_dir / "config" / "invoice_agent.yaml"
                config_artifact.parent.mkdir(parents=True, exist_ok=True)
                artifact_text = (
                    self.config_path.read_text(encoding="utf-8")
                    if self.config_path.exists()
                    else config_to_artifact_text(self.config)
                )
                config_artifact.write_text(artifact_text, encoding="utf-8")
                mlflow.log_artifact(str(config_artifact), artifact_path="config")

            if self.config.tracing.log_prompt_artifacts and self.prompt is not None:
                prompt_dir = self.run_dir / "prompts"
                prompt_dir.mkdir(parents=True, exist_ok=True)
                prompt_path = prompt_dir / "request_prompt.txt"
                if not prompt_path.exists():
                    prompt_path.write_text(self.prompt, encoding="utf-8")
                for artifact in sorted(prompt_dir.glob("*.txt")):
                    mlflow.log_artifact(str(artifact), artifact_path="prompts")
        except Exception:  # pragma: no cover - tracing must not block the run
            self._disable_git_version_tracking()
            self.enabled = False
            self._run_active = False

    def finalize(self, trace_writer: TraceWriter, report: dict[str, Any] | None) -> None:
        if not self.enabled:
            self._disable_git_version_tracking()
            return

        try:
            if self.config.tracing.log_trace_artifacts:
                if trace_writer.trace_path.exists():
                    mlflow.log_artifact(str(trace_writer.trace_path), artifact_path="traces")
                if trace_writer.sse_path.exists():
                    mlflow.log_artifact(str(trace_writer.sse_path), artifact_path="traces")

            final_report_path = trace_writer.run_dir / "final_report.json"
            if final_report_path.exists():
                mlflow.log_artifact(str(final_report_path), artifact_path="outputs")

            if report:
                summary = report.get("run_summary", {})
                mlflow.log_metric("invoice_count", float(summary.get("invoice_count", 0)))
                mlflow.log_metric("total_spend", float(summary.get("total_spend", 0.0)))

            if self._run_active:
                mlflow.end_run(status="FINISHED")
                self._run_active = False
        except Exception:  # pragma: no cover - tracing must not block the run
            self.enabled = False
            self._run_active = False
        finally:
            self._disable_git_version_tracking()

    def finalize_error(self, trace_writer: TraceWriter, error: dict[str, Any]) -> None:
        if not self.enabled:
            self._disable_git_version_tracking()
            return

        try:
            error_path = trace_writer.run_dir / "errors" / "error.json"
            error_path.parent.mkdir(parents=True, exist_ok=True)
            error_path.write_text(json.dumps(error, indent=2), encoding="utf-8")
            mlflow.log_artifact(str(error_path), artifact_path="errors")

            if self.config.tracing.log_trace_artifacts:
                if trace_writer.trace_path.exists():
                    mlflow.log_artifact(str(trace_writer.trace_path), artifact_path="traces")
                if trace_writer.sse_path.exists():
                    mlflow.log_artifact(str(trace_writer.sse_path), artifact_path="traces")

            if self._run_active:
                mlflow.end_run(status="FAILED")
                self._run_active = False
        except Exception:  # pragma: no cover - tracing must not block the run
            self.enabled = False
            self._run_active = False
        finally:
            self._disable_git_version_tracking()

    def version_tracking_payload(self) -> dict[str, Any] | None:
        if self.version_tracking is None:
            return None
        return self.version_tracking.to_payload()

    def _bootstrap_git_version_tracking(self) -> None:
        if mlflow is None or not hasattr(mlflow, "genai"):
            return

        try:
            context = mlflow.genai.enable_git_model_versioning()
            info = getattr(context, "info", None)
            active_model = getattr(context, "active_model", None)
            if info is None or active_model is None:
                return

            model_id = getattr(active_model, "model_id", None) or mlflow.get_active_model_id()
            if model_id is None:
                return

            self.version_tracking = VersionTrackingMetadata(
                model_id=str(model_id),
                model_name=getattr(active_model, "name", None),
                git_branch=getattr(info, "branch", None),
                git_commit=getattr(info, "commit", None),
                git_dirty=getattr(info, "dirty", None),
                git_repo_url=getattr(info, "repo_url", None),
                search_filter_string=getattr(info, "to_search_filter_string", lambda: None)(),
                git_tags=self._build_git_tags(info),
            )
            self._git_versioning_enabled = True
        except Exception:  # pragma: no cover - version tracking must not block the run
            self.version_tracking = None
            self._git_versioning_enabled = False

    def _build_git_tags(self, info: Any) -> dict[str, str]:
        tags: dict[str, str] = {}
        branch = getattr(info, "branch", None)
        commit = getattr(info, "commit", None)
        dirty = getattr(info, "dirty", None)
        repo_url = getattr(info, "repo_url", None)

        if branch is not None:
            tags["mlflow.source.git.branch"] = str(branch)
        if commit is not None:
            tags["mlflow.source.git.commit"] = str(commit)
        if dirty is not None:
            tags["mlflow.source.git.dirty"] = "true" if dirty else "false"
        if repo_url is not None:
            tags["mlflow.source.git.repoURL"] = str(repo_url)
        return tags

    def _log_version_tracking_tags(self) -> None:
        if self.version_tracking is None:
            return

        for key, value in self.version_tracking.git_tags.items():
            mlflow.set_tag(key, value)
        mlflow.set_tag("mlflow.active_model_id", self.version_tracking.model_id)
        if self.version_tracking.model_name:
            mlflow.set_tag("mlflow.active_model_name", self.version_tracking.model_name)
        mlflow.set_tag("mlflow.version_tracking.enabled", "true")

    def _disable_git_version_tracking(self) -> None:
        if not self._git_versioning_enabled or mlflow is None or not hasattr(mlflow, "genai"):
            return

        try:
            mlflow.genai.disable_git_model_versioning()
        except Exception:  # pragma: no cover - cleanup should never block tracing
            pass
        finally:
            self._git_versioning_enabled = False

